    // Connect to the SQLite database
    auto db = sqlgen::sqlite::connect("test_db.sqlite");

    // Create table references for Product and Sale
    sqlgen::Table<Product> p("Product");
    sqlgen::Table<Sale> s("Sale");

    // Build the query with JOIN, GROUP BY, and HAVING clauses
    auto query = sqlgen::select(
        p.category,
        sqlgen::sum(s.quantity).as("total_qty"),
        sqlgen::sum(s.amount).as("total_amt")
    )
    .from(p)
    .inner_join(s).on(p.product_id == s.product_id)
    .group_by(p.category)
    .having(sqlgen::sum(s.amount) > 5000);

    // Execute the query and return results as vector of CategoryReport
    return db.execute<CategoryReport>(query);
}

}  // namespace query_product_sales_report
