```cpp
#pragma once

#include <optional>
#include <rfl.hpp>
#include <rfl/json.hpp>
#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <string>
#include <vector>

namespace query_search_books_by_criteria {

struct Book {
  sqlgen::PrimaryKey<int> book_id;
  std::string title;
  std::string author;
  int year;
  std::string genre;
  double price;
};

struct BookFilters {
  std::optional<std::string> title_keyword;
  std::optional<int> min_year;
  std::optional<std::string> genre;
  std::optional<double> max_price;
};

/**
 * Function: Search for books based on multiple optional criteria.
 * 
 * @param filters Optional filters for title, year, genre, and price
 * @return List of books matching the criteria
 */
std::vector<Book> query_search_books_by_criteria(const BookFilters& filters) {
    // Connect to the SQLite database
    auto db = sqlgen::sqlite::Database("test_db.sqlite");

    // Start with a base SELECT query
    auto query = db.select<Book>();

    // Add WHERE clauses dynamically based on non-null input parameters

    // Use LIKE for title search
    if (filters.title_keyword.has_value()) {
        std::string pattern = "%" + filters.title_keyword.value() + "%";
        query = query.where([pattern](const Book& b) {
            return sqlgen::like(b.title, pattern);
        });
    }

    // Use >= comparison for minimum year
    if (filters.min_year.has_value()) {
        int min_year_val = filters.min_year.value();
        query = query.where([min_year_val](const Book& b) {
            return b.year >= min_year_val;
        });
    }

    // Use = comparison for genre
    if (filters.genre.has_value()) {
        std::string genre_val = filters.genre.value();
        query = query.where([genre_val](const Book& b) {
            return b.genre == genre_val;
        });
    }

    // Use <= comparison for maximum price
    if (filters.max_price.has_value()) {
        double max_price_val = filters.max_price.value();
        query = query.where([max_price_val](const Book& b) {
            return b.price <= max_price_val;
        });
    }

    // Execute query and return results
    return query.execute();
}

}  // namespace query_search_books_by_criteria
```

