  std::cout << "\n=== Query 3: Friend-of-Friend Recommendations ===" << std::endl;
  auto fof_query = db.query(R"(
    SELECT DISTINCT u1.username as user_name, u3.username as friend_of_friend
    FROM User u1
    INNER JOIN Friendship f1 ON u1.user_id = f1.user_id1
    INNER JOIN Friendship f2 ON f1.user_id2 = f2.user_id1
    INNER JOIN User u3 ON f2.user_id2 = u3.user_id
    WHERE u1.user_id != u3.user_id
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f3
        WHERE f3.user_id1 = u1.user_id AND f3.user_id2 = u3.user_id
      )
    ORDER BY u1.username, u3.username
  )");

  while (fof_query.next()) {
    std::string user_name = fof_query.get<std::string>(0);
    std::string fof_name = fof_query.get<std::string>(1);
    std::cout << user_name << " -> " << fof_name << " (friend-of-friend)" << std::endl;
  }

  // Query 4: Count friends per user and identify most connected users
  std::cout << "\n=== Query 4: Network Statistics - Friend Count ===" << std::endl;
  auto friend_stats = db.query(R"(
    SELECT u.username, COUNT(f.user_id2) as friend_count
    FROM User u
    LEFT JOIN Friendship f ON u.user_id = f.user_id1
    GROUP BY u.user_id, u.username
    ORDER BY friend_count DESC
  )");

  while (friend_stats.next()) {
    std::string username = friend_stats.get<std::string>(0);
    int friend_count = friend_stats.get<int>(1);
    std::cout << username << ": " << friend_count << " friends" << std::endl;
  }

  // Query 5: Find users in same city who are not yet friends (recommendation)
  std::cout << "\n=== Query 5: Same City Friend Recommendations ===" << std::endl;
  auto city_recommendations = db.query(R"(
    SELECT u1.username as user1_name, u2.username as user2_name, u1.city
    FROM User u1
    INNER JOIN User u2 ON u1.city = u2.city
    WHERE u1.user_id < u2.user_id
      AND u1.city IS NOT NULL
      AND NOT EXISTS (
        SELECT 1 FROM Friendship f
        WHERE (f.user_id1 = u1.user_id AND f.user_id2 = u2.user_id)
           OR (f.user_id1 = u2.user_id AND f.user_id2 = u1.user_id)
      )
    ORDER BY u1.city, u1.username
  )");

  while (city_recommendations.next()) {
    std::string user1 = city_recommendations.get<std::string>(0);
    std::string user2 = city_recommendations.get<std::string>(1);
    std::string city = city_recommendations.get<std::string>(2);
    std::cout << "Recommend: " << user1 << " <-> " << user2 << " (both in " << city << ")" << std::endl;
  }

  // Additional analysis: Find network density
  std::cout << "\n=== Query 6: Network Density Analysis ===" << std::endl;
  auto density_query = db.query(R"(
    SELECT 
      COUNT(DISTINCT user_id1) as total_users,
      COUNT(*) as total_friendships,
      AVG(friend_count) as avg_friends_per_user
    FROM Friendship
    CROSS JOIN (
      SELECT COUNT(*) as friend_count 
      FROM Friendship 
      GROUP BY user_id1
    )
  )");

  if (density_query.next()) {
    int total_users = density_query.get<int>(0);
    int total_friendships = density_query.get<int>(1);
    double avg_friends = density_query.get<double>(2);
    std::cout << "Total users: " << total_users << std::endl;
    std::cout << "Total friendships: " << total_friendships << std::endl;
    std::cout << "Average friends per user: " << avg_friends << std::endl;
  }

  return results;
}

