  // Execute query and fetch results
  while (query.step()) {
    MathAnalysis analysis;
    analysis.product_id = query.column<int>(0);
    analysis.name = query.column<std::string>(1);
    analysis.abs_price = query.column<double>(2);
    analysis.ceil_price = query.column<double>(3);
