```cpp
#pragma once

#include <sqlgen.hpp>
#include <sqlgen/sqlite.hpp>
#include <vector>
#include <optional>

namespace full_join_suppliers_products {

struct Supplier {
  sqlgen::PrimaryKey<int> supplier_id;
  std::string name;
};

struct Product {
  sqlgen::PrimaryKey<int> product_id;
  int supplier_id;
  std::string name;
};

struct SupProd {
  std::string supplier_name;
  std::optional<std::string> product_name;
};

/**
 * Returns a vector of SupProd structs, where each struct contains the name of a supplier and the name of a product, if any.
 */
std::vector<SupProd> full_join_suppliers_products() {
  // Connect to the SQLite database
  sqlgen::sqlite::Connection conn("test_db.sqlite");

  // SQLite doesn't natively support FULL OUTER JOIN, so we simulate it
  // using LEFT JOIN combined with UNION to get products without suppliers
  std::string query = R"(
    SELECT s.name as supplier_name, p.name as product_name
    FROM Supplier s 
    LEFT JOIN Product p ON s.supplier_id = p.supplier_id
    UNION ALL
    SELECT COALESCE(s.name, '') as supplier_name, p.name as product_name
    FROM Product p 
    LEFT JOIN Supplier s ON p.supplier_id = s.supplier_id
    WHERE s.supplier_id IS NULL
  )";

  // Execute the query
  auto stmt = conn.prepare(query);
  auto result = stmt.execute();

  // Process results
  std::vector<SupProd> results;
  while (result.next()) {
    SupProd sp;
    sp.supplier_name = result.template get<std::string>(0);

    // product_name might be NULL for suppliers without products
    if (result.is_null(1)) {
      sp.product_name = std::nullopt;
    } else {
      sp.product_name = result.template get<std::string>(1);
    }

    results.push_back(sp);
  }

  return results;
}

}  // namespace full_join_suppliers_products
```

**Key points of the implementation:**

1. **Database Connection**: Opens connection to "test_db.sqlite" using `sqlgen::sqlite::Connection`

2. **FULL JOIN Simulation**: Since SQLite doesn't support FULL OUTER JOIN natively, the query uses:
   - `LEFT JOIN` to get all suppliers with their products (if any)
   - `UNION ALL` combined with another `LEFT JOIN` to get products without matching suppliers
   - `WHERE s.supplier_id IS NULL` filters to only orphaned products

3. **Result Processing**: 
   - Iterates through query results
   - Handles NULL product names using `std::optional`
   - Uses `COALESCE(s.name, '')` for products without suppliers to ensure supplier_name is never null

4. **Return Value**: Vector of `SupProd` structs containing all supplier-product combinations from both tables

