  .from(product)
  .inner_join(sales).on(product.product_id == sales.product_id)
  .group_by(product.product_id, product.product_name, product.category)
  .order_by(sqlgen::desc("total_sales"))
  .limit(limit_count);

  // Execute the query and map each row to a TopProduct object
  auto results = db.execute(query);
  std::vector<TopProduct> top_products;
  for (const auto& row : results) {
